            .hemo-alert { padding: 14px 18px; border-radius: 12px; margin-bottom: 20px; background: rgba(234,179,8,0.08); border: 1px solid rgba(234,179,8,0.25); font-size: 13px; color: #fbbf24; display: flex; align-items: center; gap: 10px; justify-content: space-between; }
