          <div className="hemo-home">
            <div className="hemo-greeting">
              <div className="hemo-greeting-hi">
                Hey,{" "}
                <span className="hemo-greeting-name">
                  {user?.name ||
                    user?.organisationName ||
                    user?.hospitalName ||
                    "there"}
                </span>{" "}
                👋
                <span className="hemo-live">
                  <div className="hemo-live-dot" /> Live
                </span>
              </div>
              <div className="hemo-greeting-sub">
                {isOrg
                  ? "Manage your blood inventory below"
                  : isHospital
                    ? "Track blood requests and availability"
                    : "Welcome to HemoLink — every drop counts 🩸"}
              </div>
            </div>

            {/* Hospital pending requests alert */}
            {isHospital && pendingRequests > 0 && (
              <div className="hemo-alert">
                <span>
                  🟡 You have{" "}
                  <strong>
                    {pendingRequests} pending request
                    {pendingRequests > 1 ? "s" : ""}
                  </strong>{" "}
                  waiting for organisation approval
                </span>
                <a href="/consumer" className="hemo-alert-link">
                  View status →
                </a>
              </div>
            )}

            {/* Stats */}
            <div className="hemo-stats">
              {isHospital ? (
                <>
                  <div className="hemo-stat-card yellow">
                    <div className="hemo-stat-icon">🟡</div>
                    <div className="hemo-stat-num">{pendingRequests}</div>
                    <div className="hemo-stat-label">Pending Requests</div>
                  </div>
                  <div className="hemo-stat-card green">
                    <div className="hemo-stat-icon">✅</div>
                    <div className="hemo-stat-num">{acceptedRequests}</div>
                    <div className="hemo-stat-label">Accepted Requests</div>
                  </div>
                  <div className="hemo-stat-card pink">
                    <div className="hemo-stat-icon">🏢</div>
                    <div className="hemo-stat-num">{totalOrgs}</div>
                    <div className="hemo-stat-label">Blood Banks Available</div>
                  </div>
                  <div className="hemo-stat-card blue">
                    <div className="hemo-stat-icon">🏕️</div>
                    <div className="hemo-stat-num">{camps.length}</div>
                    <div className="hemo-stat-label">Active Camps</div>
                  </div>
                </>
              ) : (
                <>
                  <div className="hemo-stat-card purple">
                    <div className="hemo-stat-icon">🩸</div>
                    <div className="hemo-stat-num">
                      {data.length}
                      <span>+</span>
                    </div>
                    <div className="hemo-stat-label">
                      {isDonor ? "Your Donations" : "Blood Records"}
                    </div>
                  </div>
                  <div className="hemo-stat-card pink">
                    <div className="hemo-stat-icon">🏢</div>
                    <div className="hemo-stat-num">{totalOrgs}</div>
                    <div className="hemo-stat-label">
                      Organisations on HemoLink
                    </div>
                  </div>
                  <div className="hemo-stat-card blue">
                    <div className="hemo-stat-icon">🏕️</div>
                    <div className="hemo-stat-num">{camps.length}</div>
                    <div className="hemo-stat-label">Active Camps Near You</div>
                  </div>
                </>
              )}
            </div>

            <div className="hemo-fact-card">
              <div className="hemo-fact-icon">{facts[factIndex].icon}</div>
              <div>
                <div className="hemo-fact-label">Did you know?</div>
                <div className="hemo-fact-text">{facts[factIndex].text}</div>
              </div>
            </div>

            <div className="hemo-privacy">
              <div className="hemo-privacy-icon">🔒</div>
              <div>
                <div className="hemo-privacy-title">
                  Your privacy is protected
                </div>
                <div className="hemo-privacy-text">
                  Hospitals and organisations only see your blood type — never
                  your name, phone number, or address. Your personal information
                  is encrypted and never shared.
                </div>
              </div>
            </div>

            <div className="hemo-two-col">
              <div className="hemo-card">
                <div className="hemo-card-title">
                  {isHospital
                    ? "📋 Recent Blood Requests"
                    : isOrg
                      ? "🗃️ Blood Inventory"
                      : "🩸 Your Recent Donations"}
                </div>
                {isOrg && (
                  <button
                    className="hemo-add-btn"
                    data-bs-toggle="modal"
                    data-bs-target="#staticBackdrop"
                  >
                    + Add Inventory
                  </button>
                )}
                {isHospital ? (
                  hospitalRequests.length === 0 ? (
                    <div className="hemo-empty">
                      <div style={{ fontSize: 32, marginBottom: 8 }}>📋</div>
                      <div>No requests yet</div>
                      <a
                        href="/orgnaisation"
                        className="hemo-donate-link"
                        style={{ marginTop: 14 }}
                      >
                        Request Blood →
                      </a>
                    </div>
                  ) : (
                    <table className="hemo-table">
                      <thead>
                        <tr>
                          <th>Blood</th>
                          <th>Qty</th>
                          <th>Organisation</th>
                          <th>Status</th>
                        </tr>
                      </thead>
                      <tbody>
                        {hospitalRequests.slice(0, 6).map((req) => (
                          <tr key={req._id}>
                            <td>
                              <span className="hemo-badge hemo-badge-blood">
                                {req.bloodGroup}
                              </span>
                            </td>
                            <td>{req.quantity} ml</td>
                            <td style={{ fontSize: 12 }}>
                              {req.organisation?.organisationName || "—"}
                            </td>
                            <td>
                              <span
                                className={`hemo-badge hemo-badge-${req.status}`}
                              >
                                {req.status === "pending"
                                  ? "🟡 Pending"
                                  : req.status === "accepted"
                                    ? "✅ Accepted"
                                    : "❌ Rejected"}
                              </span>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  )
                ) : data.length === 0 ? (
                  <div className="hemo-empty">
                    {isDonor ? (
                      <>
                        <div style={{ fontSize: 36, marginBottom: 8 }}>🩸</div>
                        <div>No donations yet!</div>
                        <a
                          href="/donation"
                          className="hemo-donate-link"
                          style={{ marginTop: 14 }}
                        >
                          Record Donation →
                        </a>
                      </>
                    ) : (
                      <div>No records yet</div>
                    )}
                  </div>
                ) : (
                  <table className="hemo-table">
                    <thead>
                      <tr>
                        <th>Blood</th>
                        <th>Type</th>
                        <th>Qty (ml)</th>
                        <th>Date</th>
                      </tr>
                    </thead>
                    <tbody>
                      {data.slice(0, 6).map((record) => (
                        <tr key={record._id}>
                          <td>
                            <span className="hemo-badge hemo-badge-blood">
                              {record.bloodGroup}
                            </span>
                          </td>
                          <td>
                            <span
                              className={`hemo-badge ${record.inventoryType === "in" ? "hemo-badge-in" : "hemo-badge-out"}`}
                            >
                              {record.inventoryType === "in"
                                ? "Donated"
                                : "Used"}
                            </span>
                          </td>
                          <td>{record.quantity}</td>
                          <td>
                            {moment(record.createdAt).format("DD MMM YY")}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                )}
              </div>

              <div className="hemo-card">
                <div className="hemo-card-title">
                  {isHospital
                    ? "🏥 How to Request Blood"
                    : "🩸 How to Donate Blood"}
                </div>
                {isHospital ? (
                  <div className="hemo-steps">
                    {[
                      [
                        "Check Availability",
                        "Go to Blood Availability in the sidebar to see live stock",
                      ],
                      [
                        "Click a Blood Group",
                        "Click any purple pill to open the request form",
                      ],
                      [
                        "Submit Request",
                        "Fill in quantity and submit — it goes to the organisation",
                      ],
                      [
                        "Wait for Approval",
                        "The org will accept or reject — you'll see status update here live",
                      ],
                      [
                        "Blood Dispatched",
                        "Once accepted, blood is marked as sent from their inventory ✅",
                      ],
                    ].map(([title, desc], i) => (
                      <div className="hemo-step" key={i}>
                        <div className="hemo-step-num">{i + 1}</div>
                        <div className="hemo-step-text">
                          <strong>{title}:</strong> {desc}
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="hemo-steps">
                    {[
                      [
                        "Register",
                        "Create your HemoLink donor account (done! ✅)",
                      ],
                      [
                        "Find a Camp",
                        "Check active camps below — all verified by registered orgs",
                      ],
                      [
                        "Visit & Donate",
                        "Walk in — the whole process takes 10–15 mins",
                      ],
                      [
                        "Record It",
                        "Log your donation under My Donations page",
                      ],
                      [
                        "Rest & Hydrate",
                        "Drink water, have a snack. You're a hero! 🎉",
                      ],
                    ].map(([title, desc], i) => (
                      <div className="hemo-step" key={i}>
                        <div className="hemo-step-num">{i + 1}</div>
                        <div className="hemo-step-text">
                          <strong>{title}:</strong> {desc}
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>

            <div className="hemo-card" style={{ marginBottom: 28 }}>
              <div className="hemo-section-title">
                📍 Blood Donation Camps Near You
              </div>
              <p
                style={{
                  fontSize: 13,
                  color: "rgba(255,255,255,0.35)",
                  marginBottom: 16,
                }}
              >
                All camps below are organised by verified blood banks registered
                on HemoLink.
              </p>
              {camps.length === 0 ? (
                <div className="hemo-empty">
                  No active camps right now — check back soon!
                </div>
              ) : (
                camps.map((camp) => (
                  <div className="hemo-camp-card" key={camp._id}>
                    <div className="hemo-camp-icon">🏕️</div>
                    <div>
                      <div className="hemo-camp-name">
                        {camp.campName}
                        <span className="hemo-camp-badge">Active</span>
                      </div>
                      <div className="hemo-camp-addr">📍 {camp.address}</div>
                      <div className="hemo-camp-date">
                        📅 {moment(camp.date).format("DD MMM YYYY")} &nbsp; 🕐{" "}
                        {camp.time}
                      </div>
                      <div className="hemo-camp-org">
                        ✅ By: {camp.organisation?.organisationName}
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
          <Modal />
        </>
      )}
    </Layout>
  );
};

export default HomePage;
